def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.5:
            if ratio < 2.2:
                priority = (ratio - 1.5) ** 3 * 280 + 25
                for j in range(1, 5):
                    priority += ((-1) ** (j+1)) * np.cos(np.pi * ratio * j * 0.8) * (j**1.1)
                if capacity % 9 == 0:
                    priority += 4.5
                if capacity % 11 == 0:
                    priority += 3.3
                for m in range(2,7):
                    if m % 2 == 0:
                        priority += (m * 0.4) / (ratio ** (m*0.7) + 1)
                    else:
                        priority -= (m * 0.3) * np.exp(-ratio * m)
            elif ratio < 3.0:
                priority = (ratio - 2.2) * 260 + 80
                if capacity % 5 == 0:
                    priority += 1.8
                else:
                    priority += 0.9
                for k in range(1, 6):
                    weight = ((-1) ** k) * np.sin(ratio * k * np.pi / 2) / (k + capacity % 3 + 1)
                    priority += weight * 2.5
                if ratio > 2.7:
                    priority += ((ratio - 2.7) ** 2) * 15
            else:
                priority = np.inf
        else:
            acc = 0
            for n in range(1, 12):
                sign = (-1) ** (n+1)
                power_base = ratio ** (n * 1.3)
                divisor = np.sqrt(n * capacity + 1)
                mod_factor = 1.5 if n % 4 == 0 else 1.0
                acc += sign * power_base / divisor * mod_factor
            priority += abs(acc) * 2.2
            if capacity < item * 1.5:
                priority *= 3.2
            log_diff = np.log(capacity + 5) - np.log(item + 0.9)
            if log_diff > 0:
                priority += 12 / log_diff
            else:
                priority += 38
            mods = [capacity % m == 0 for m in [2,3,5,7,10]]
            if mods[4]:
                priority += 1.6
            elif mods[3]:
                priority += 1.3
            elif mods[2]:
                priority += 1.0
            elif mods[1]:
                priority += 0.7
            elif mods[0]:
                priority += 0.4
            else:
                priority -= 0.6
            if ratio < 0.3:
                for p in range(1, 7):
                    term = ((-1) ** p) * (ratio ** (p * 2.1)) * (p * 0.6)
                    if p == 5 and capacity > item * 8:
                        term *= 1.8
                    priority += term
            if capacity > 5 * item and capacity < 12 * item:
                penalty = 0
                for q in range(3, 8):
                    penalty += np.log(q + capacity) * ((-1) ** q) * (ratio ** (1 / q))
                priority -= penalty * 1.4
            if capacity > item * 15:
                for r in range(2, 10):
                    scale = r * 0.25
                    sign = (-1) ** (r + 1)
                    priority += sign * (ratio ** (1 / r)) * np.sqrt(r) * scale
            if priority > 75:
                priority = 75 + np.sqrt(np.log(priority - 74) + 1) * 2.0
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
